  ('social-worker-moex-02021', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Mary Ainsworth（1978）提及依附理論時認為，嬰兒會將主要照顧者視為基地，需要探索環境時離開，需 要安慰及安全感時返回，進而將嬰兒的反應分為不同的依附模式。若嬰兒在母親離開時會生氣，哭泣許 久；在母親回來後，雖會尋求肢體上的接觸，但可能即刻推開，甚至打母親或不易安撫。請問，此為何 種依附模式？', '["安全型依附", "焦慮型依附", "迴避型依附", "壓力型依附"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02022', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '密集性家庭維繫服務目的是增強家庭成員解決風險與問題的能力。下列何者不是密集性家庭維繫服務的 主要目標？', '["治療家庭", "保護兒童", "穩定危機情況", "增強家庭成員的技巧與能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02023', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關基因與環境對人類行為的影響，下列敘述何者正確？', '["同一家庭的兄弟姐妹因為生活環境層面相似，故會有相似的行為", "人類行為的差異（例如智力和人格特質）完全是因為社會環境的影響", "人們會去找尋符合其基因優勢的環境", "社會工作者不需要評估個案的遺傳基因問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02024', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '人類能因應環境的變化，是因為人類已做了學習的準備；其中，新的反應是可以透過對榜樣的觀察和模 仿而習得。請問，以上是符合那一論點？', '["古典制約", "操作制度", "社會學習", "認知行為主義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02025', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「當施虐者累積壓力到一定程度，無法控制情緒及行為時，會有暴力行為出現使得部分壓力得以紓解， 進而與受暴者有一段蜜月期；但是，施虐者隨著壓力的累積，仍有暴力行為的出現。」以上有關親密關 係暴力的討論，符合何項觀點的敘述？', '["暴力循環理論", "依附理論", "家庭壓力理論", "社會學習理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02026', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「學齡兒童可能因父母離異而出現焦慮或情緒調適之困難，但是也有可能在瞭解離異事件背後的因素， 而表現得更為成熟、正向、積極地面對生活。」這樣的生活適應符合下列何項觀點？', '["習得無助感", "復原力", "觀點取替能力", "社交勝任能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02027', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「有關親密關係的處遇中，有越來越多的社會服務單位針對暴力行為對目睹兒童行為影響進行處理及協 助，避免兒童習得暴力行為，影響其同儕相處，甚至是日後的兩性及家庭關係建立」。以上敘述符合下 列何項觀點？', '["家庭生命週期", "依附理論", "認知發展理論", "暴力的代間傳遞循環理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02028', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於青少年時期評估發展內容，下列敘述何者錯誤？', '["大腦發育及抽象思考", "同儕團體", "物體恆存概念", "性認同的情況"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02029', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '以下有關青少年「從依賴到獨立」發展特色的敘述，何者有誤？', '["青少年在社交獨立的發展上，通常是由自我主導到他人引導", "獨立可分為社交、情感與經濟獨立", "青少年無特殊技能，尚無法獲得較高薪的工作以支應其財務的需求，經濟獨立對大部分青少年而言， 是困難的", "情感獨立係指從對父母或其他人的情感依賴逐漸自我獨立，但仍能維持原有之親密關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02030', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年是國家重要的資產，以下針對青少年就業與就學的討論，何者錯誤？', '["家庭、學校及相關系統能否提供適切的協助資源，是讓青少年穩定就學或順利就業的重要關鍵", "針對無升學意願或有就業意願的青少年，政府應提供其進入職場的工作機會，才不至於造成人力資源 的浪費", "青少年若能穩定就學或是順利就業，將有利於他們的自我認同與生涯發展", "許多青少年未升學、未就業的原因都是家庭經濟狀況不佳或不適應學校正規教育"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02031', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '學齡兒童期（6-12 歲）是語言能力發展更加精熟的時期，這時期的兒童會用較開放式的回答，並瞭解字 詞的抽象能力，此種能力的發展也能幫助孩子欣賞幽默和笑話。上述能力指的是：', '["形而上的語言覺知能力", "形而下的語言覺知能力", "隱喻的能力", "明喻的能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02032', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '身心障礙者之照顧者的身體及心理壓力負荷情形是倍受關注的議題。照顧者也需要由他人短暫協助照顧 工作，使其有紓解壓力的機會。那一項服務符合上述照顧者的需要？', '["自立生活支持服務", "喘息服務", "課後照顧", "日間及住宿式照顧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02033', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於成年前期發展的里程碑，下列敘述何者錯誤？', '["專業及生涯的發展", "生活經驗的回顧及展望", "經濟和生活的獨立", "親密關係的發展或家庭的建立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02034', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '專業人員為兒童提供服務時，需協助兒童面對可能引起複雜情緒和創傷的事件，同時，專業人員需顧及 兒童無法理解成人視為理所當然的因果概念，必須以他們能夠理解的方式和語詞解釋。請問，上述兒童 屬於皮亞傑的認知理論中的那一個階段？', '["感覺動作期", "前運思期", "具體運思期", "正式運思期"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02035', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者是生命晚期家庭之核心發展任務？', '["接受新的家庭成員", "接受孩子的獨立及祖父母的衰退", "接受成員從家庭系統移出和加入", "接受代間角色的轉移"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "1ded24a4d2e0", "answer_pdf_sha1": "688221b2a150", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
